const ctx = items[0].json;

if (!ctx.obsidian_rest_url || !ctx.obsidian_rest_api_key) {
  throw new Error('Missing OBSIDIAN_REST_URL or OBSIDIAN_REST_API_KEY');
}

const baseUrl = String(ctx.obsidian_rest_url).replace(/\/+$/, '');

function vaultUrl(path) {
  return baseUrl + '/vault/' + encodeURI(path);
}

async function obsidianGet(path) {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: vaultUrl(path),
    headers: {
      Authorization: 'Bearer ' + ctx.obsidian_rest_api_key,
    },
    json: false,
    skipSslCertificateValidation: !!ctx.allow_insecure_tls,
  });
}

async function obsidianPut(path, body) {
  return await this.helpers.httpRequest({
    method: 'PUT',
    url: vaultUrl(path),
    headers: {
      Authorization: 'Bearer ' + ctx.obsidian_rest_api_key,
      'Content-Type': 'text/markdown',
    },
    body,
    json: false,
    skipSslCertificateValidation: !!ctx.allow_insecure_tls,
  });
}

async function readRequiredTextFile(path) {
  try {
    const text = await obsidianGet.call(this, path);
    if (!text || !String(text).trim()) {
      throw new Error('Prompt file is empty: ' + path);
    }
    return String(text).trim();
  } catch (error) {
    const status = Number(
      (error && (error.statusCode || error.status || error.httpCode)) ||
      (error && error.response ? (error.response.status || error.response.statusCode || 0) : 0)
    );
    const isNotFound = status === 404 || /status code 404|\b404\b/i.test(String(error && error.message ? error.message : ''));
    if (isNotFound) {
      throw new Error('Required prompt file missing: ' + path);
    }
    throw new Error('Obsidian read failed for "' + path + '": ' + (error.message || 'unknown error'));
  }
}

const promptPaths = {
  agent1_research: ctx.workflow_prompts_dir + '/agent1_research.md',
  agent2_topic_fit: ctx.workflow_prompts_dir + '/agent2_topic_fit.md',
  agent3_draft: ctx.workflow_prompts_dir + '/agent3_draft.md',
  agent4_ai_sounding_critic: ctx.workflow_prompts_dir + '/agent4_ai_sounding_critic.md',
  agent6_strategy_critic: ctx.workflow_prompts_dir + '/agent6_strategy_critic.md',
  agent7_strategy_critic: ctx.workflow_prompts_dir + '/agent7_strategy_critic.md',
  platform_linkedin: ctx.workflow_prompts_dir + '/platform_linkedin.md',
  platform_reddit: ctx.workflow_prompts_dir + '/platform_reddit.md',
  qwen_step_summary: ctx.workflow_prompts_dir + '/qwen_step_summary.md',
};

for (const [key, path] of Object.entries(promptPaths)) {
  ctx.prompts[key] = await readRequiredTextFile.call(this, path);
}

return [{ json: ctx }];

const ctx = items[0].json;

const primaryModel = String(ctx.model_primary || 'qwen3.5:27b');
let activeModel = primaryModel;

function nowIso() {
  return new Date().toISOString();
}

function shortText(value, maxLen = 320) {
  const text = (typeof value === 'string') ? value : JSON.stringify(value || '');
  if (text.length <= maxLen) return text;
  return text.slice(0, maxLen - 3) + '...';
}

function clamp(value, min, max, fallback) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  if (n < min) return min;
  if (n > max) return max;
  return n;
}

function sanitizeSlug(value) {
  return String(value || 'workflow')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || 'workflow';
}

function yamlEscape(value) {
  return String(value || '').replace(/\n/g, ' ').replace(/"/g, '\\"');
}

function ensureArray(value) {
  return Array.isArray(value) ? value : [];
}

function extractJsonCandidate(rawText) {
  if (typeof rawText !== 'string') {
    throw new Error('Model output is not a string');
  }

  const fenced = rawText.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const text = (fenced ? fenced[1] : rawText).trim();

  try {
    return JSON.parse(text);
  } catch (error) {
    // continue below
  }

  const objStart = text.indexOf('{');
  const arrStart = text.indexOf('[');
  const starts = [objStart, arrStart].filter((v) => v >= 0);
  if (!starts.length) {
    throw new Error('No JSON start found');
  }

  const start = Math.min(...starts);
  const firstChar = text[start];
  const openChar = firstChar;
  const closeChar = firstChar === '{' ? '}' : ']';

  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = start; i < text.length; i++) {
    const ch = text[i];

    if (inString) {
      if (escaped) {
        escaped = false;
      } else if (ch === '\\') {
        escaped = true;
      } else if (ch === '"') {
        inString = false;
      }
      continue;
    }

    if (ch === '"') {
      inString = true;
      continue;
    }

    if (ch === openChar) depth += 1;
    if (ch === closeChar) {
      depth -= 1;
      if (depth === 0) {
        const candidate = text.slice(start, i + 1);
        return JSON.parse(candidate);
      }
    }
  }

  throw new Error('Could not extract valid JSON payload');
}

async function callOllamaRaw(systemPrompt, userPrompt, options = {}) {
  const temperature = Number.isFinite(Number(options.temperature)) ? Number(options.temperature) : 0.3;
  const numPredict = Number.isFinite(Number(options.num_predict)) ? Number(options.num_predict) : 180;
  const numCtx = Number.isFinite(Number(options.num_ctx)) ? Number(options.num_ctx) : 768;
  const timeout = Number.isFinite(Number(options.timeout)) ? Number(options.timeout) : 900000;
  const maxAttempts = Number.isFinite(Number(options.max_attempts)) ? Number(options.max_attempts) : 3;
  const keepAlive = String(options.keep_alive || '30m');
  const warmupPing = String(options.warmup_ping || 'return {"ok":true}');

  async function warmModel() {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: (($env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434').replace(/\/+$/, '') + '/api/chat'),
        body: {
          model: activeModel,
          stream: false,
          keep_alive: keepAlive,
          messages: [
            { role: 'system', content: 'You are a lightweight warmup responder. Reply with {"ok":true}.' },
            { role: 'user', content: warmupPing },
          ],
          options: {
            temperature: 0,
            num_predict: 12,
            num_ctx: 256,
          },
        },
        json: true,
        timeout: 120000,
      });
      console.log('[WF90_OLLAMA_WARMUP] run_id=' + ctx.run_id + ' model=' + activeModel + ' status=ok');
    } catch (error) {
      console.log('[WF90_OLLAMA_WARMUP] run_id=' + ctx.run_id + ' model=' + activeModel + ' status=skip reason=' + shortText(error && error.message ? error.message : 'unknown', 140));
    }
  }

  if (!ctx.artifacts.ollama_warmed) {
    await warmModel.call(this);
    ctx.artifacts.ollama_warmed = true;
  }

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const data = await this.helpers.httpRequest({
        method: 'POST',
        url: (($env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434').replace(/\/+$/, '') + '/api/chat'),
        body: {
          model: activeModel,
          stream: false,
          keep_alive: keepAlive,
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userPrompt },
          ],
          options: {
            temperature,
            num_predict: numPredict,
            num_ctx: numCtx,
          },
        },
        json: true,
        timeout,
      });

      const text = data && data.message ? data.message.content : data.response;
      if (!text) {
        throw new Error('Ollama response has no content');
      }

      ctx.model_used = activeModel;

      return {
        text: String(text),
        model_used: activeModel,
      };
    } catch (error) {
      let status = error && error.response && error.response.status
        ? error.response.status
        : (error && error.httpCode ? error.httpCode : 0);
      const apiError = error && error.response && error.response.data && error.response.data.error
        ? error.response.data.error
        : '';
      const details = [error && error.message ? error.message : '', apiError].filter(Boolean).join(' | ');
      if (!status) {
        const statusMatch = details.match(/status code\s+([0-9]{3})/i);
        if (statusMatch) status = Number(statusMatch[1]);
      }
      const retryable = status >= 500 || /status code\s+5[0-9]{2}|runner process has terminated|llama runner|timed out|socket hang up|econnreset|context canceled|connection reset|no content|response has no content|empty response/i.test(details);

      if (retryable && attempt < maxAttempts) {
        const waitMs = 2500 * attempt;
        console.log('[WF90_OLLAMA_RETRY] run_id=' + ctx.run_id + ' attempt=' + attempt + '/' + maxAttempts + ' wait_ms=' + waitMs + ' status=' + status);
        await new Promise((resolve) => setTimeout(resolve, waitMs));
        await warmModel.call(this);
        continue;
      }

      throw new Error(
        'Ollama call failed for "' + activeModel + '" (status=' + status + ', attempt=' + attempt + '/' + maxAttempts + '): ' + (details || 'unknown error')
      );
    }
  }
}

async function callOllamaJson(systemPrompt, userPrompt, options = {}) {
  const raw = await callOllamaRaw.call(this, systemPrompt, userPrompt, options);
  return {
    parsed: extractJsonCandidate(raw.text),
    raw_text: raw.text,
    model_used: raw.model_used,
  };
}

async function callOllamaText(systemPrompt, userPrompt, options = {}) {
  const raw = await callOllamaRaw.call(this, systemPrompt, userPrompt, options);
  return {
    text: raw.text,
    model_used: raw.model_used,
  };
}

async function callSearx(query) {
  const maxAttempts = 4;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await this.helpers.httpRequest({
        method: 'GET',
        url: 'http://searxng:8080/search',
        qs: {
          format: 'json',
          language: 'de-DE',
          q: query,
        },
        headers: {
          'User-Agent': 'Mozilla/5.0 (sandbank-workflow-research)',
        },
        json: true,
      });
    } catch (error) {
      const status = error && error.response && error.response.status
        ? error.response.status
        : (error && error.httpCode ? error.httpCode : 0);
      if (status === 429 && attempt < maxAttempts) {
        await new Promise((resolve) => setTimeout(resolve, 450 * attempt));
        continue;
      }
      throw new Error('SearXNG failed for query "' + query + '": ' + (error.message || 'request error'));
    }
  }
  throw new Error('SearXNG failed after retries for query "' + query + '"');
}

function addStage(step, stage, status, inputRef, outputRef, quality, notes, issueCount = 0) {
  if (!Array.isArray(ctx.model_trace)) ctx.model_trace = [];
  ctx.model_trace.push({
    step,
    stage,
    model_used: ctx.model_used,
    ts: nowIso(),
  });
  ctx.stage_logs.push({
    step,
    stage,
    status,
    input_ref: inputRef,
    output_ref: outputRef,
    quality_score: Number.isFinite(Number(quality)) ? Number(quality) : 0,
    notes: String(notes || ''),
    issues: Number.isFinite(Number(issueCount)) ? Number(issueCount) : 0,
    model_used: ctx.model_used,
    ts: nowIso(),
  });
}

function assertType(label, value, type) {
  if (type === 'array') {
    if (!Array.isArray(value)) throw new Error(label + ' must be an array');
    return;
  }
  if (type === 'object') {
    if (!value || typeof value !== 'object' || Array.isArray(value)) throw new Error(label + ' must be an object');
    return;
  }
  if (typeof value !== type) {
    throw new Error(label + ' must be type ' + type);
  }
}

function assertStringArray(label, arr, minLen = 0) {
  assertType(label, arr, 'array');
  if (arr.length < minLen) throw new Error(label + ' requires at least ' + minLen + ' item(s)');
  for (let i = 0; i < arr.length; i++) {
    if (typeof arr[i] !== 'string') throw new Error(label + '[' + i + '] must be string');
  }
}

function validatePlatformResearch(label, payload) {
  assertType(label, payload, 'object');
  const required = ['core_problem', 'proof_points'];
  for (const key of required) {
    if (!(key in payload)) throw new Error(label + ' missing key: ' + key);
  }
  assertType(label + '.core_problem', payload.core_problem, 'string');
  assertStringArray(label + '.proof_points', payload.proof_points, 1);
}

function validateDraftPackageStrict(payload) {
  assertType('draft_package', payload, 'object');
  if (!('topic' in payload) || !('drafts' in payload)) {
    throw new Error('draft_package missing required keys');
  }
  assertType('draft_package.topic', payload.topic, 'string');
  assertType('draft_package.drafts', payload.drafts, 'array');
  if (payload.drafts.length < 2) throw new Error('draft_package.drafts requires at least 2 drafts');
  for (let i = 0; i < payload.drafts.length; i++) {
    const d = payload.drafts[i];
    assertType('draft_package.drafts[' + i + ']', d, 'object');
    for (const key of ['platform', 'title', 'body', 'cta']) {
      if (!(key in d)) throw new Error('draft_package.drafts[' + i + '] missing key: ' + key);
      assertType('draft_package.drafts[' + i + '].' + key, d[key], 'string');
    }
    if (!Array.isArray(d.hashtags || [])) throw new Error('draft_package.drafts[' + i + '].hashtags must be array');
    if (!Array.isArray(d.notes || [])) throw new Error('draft_package.drafts[' + i + '].notes must be array');
  }
}

async function addStageSummary(step, stage, payload) {
  const summaryPrompt = [
    ctx.prompts.qwen_step_summary,
    'Schritt: ' + step + ' - ' + stage,
    'Payload: ' + shortText(payload, 2500),
    'Antworte nur mit einer kompakten Zusammenfassung.',
  ].join('\n\n');

  let summary = '';
  try {
    const res = await callOllamaText.call(
      this,
      'Du schreibst knappe Workflow-Zusammenfassungen. Keine Markdown-Listen.',
      summaryPrompt,
      { temperature: 0.1, num_predict: 40, num_ctx: 256, timeout: 90000, max_attempts: 2 }
    );
    summary = shortText(res.text.replace(/\s+/g, ' ').trim(), 280);
  } catch (error) {
    summary = 'Zusammenfassung fehlgeschlagen: ' + shortText(error.message || 'unknown', 180);
  }

  ctx.stage_summaries.push({
    step,
    stage,
    summary,
  });
}

function validateTopicBrief(data) {
  const required = ['topic', 'angle', 'why_now', 'platform_recommendation', 'confidence'];
  for (const key of required) {
    if (!(key in data)) throw new Error('topic_brief missing key: ' + key);
  }
}

function normalizeDraftPackage(candidate, fallbackTopic) {
  if (!candidate || !Array.isArray(candidate.drafts)) {
    throw new Error('draft_package invalid: drafts missing');
  }

  const drafts = candidate.drafts.map((draft, index) => {
    return {
      platform: String(draft.platform || '').toLowerCase() || (index === 0 ? 'linkedin' : 'reddit'),
      title: String(draft.title || ('Draft ' + (index + 1))),
      body: String(draft.body || ''),
      cta: String(draft.cta || ''),
      hashtags: ensureArray(draft.hashtags).map((h) => String(h)),
      notes: ensureArray(draft.notes).map((n) => String(n)),
    };
  });

  return {
    topic: String(candidate.topic || fallbackTopic || 'Workflow Thema'),
    drafts,
  };
}

function normalizeCritique(candidate, stage) {
  const src = candidate && candidate.critique_report ? candidate.critique_report : candidate;
  if (!src || typeof src !== 'object') {
    throw new Error(stage + ' critique invalid');
  }
  const issues = ensureArray(src.issues).map((issue) => ({
    severity: ['low', 'medium', 'high'].includes(issue && issue.severity) ? issue.severity : 'medium',
    message: String(issue && issue.message ? issue.message : 'unspecified issue'),
  }));
  return {
    stage: String(src.stage || stage),
    score: clamp(src.score, 0, 10, 6),
    issues,
    improved_draft: src.improved_draft || {},
  };
}

function average(values) {
  if (!values.length) return 0;
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function compactEvidence(packets, limit = 6) {
  return ensureArray(packets).slice(0, limit).map((packet) => ({
    query: shortText(packet.query || '', 80),
    title: shortText(packet.title || '', 100),
    url: shortText(packet.url || '', 180),
    summary: shortText(packet.summary || '', 140),
    key_points: ensureArray(packet.key_points).slice(0, 1).map((p) => shortText(p, 90)),
    source_type: shortText(packet.source_type || '', 40),
  }));
}

function compactDraftPackage(pkg) {
  const draftPackage = pkg && typeof pkg === 'object' ? pkg : {};
  return {
    topic: shortText(draftPackage.topic || '', 120),
    drafts: ensureArray(draftPackage.drafts).slice(0, 2).map((draft) => ({
      platform: shortText(draft.platform || '', 20),
      title: shortText(draft.title || '', 120),
      body: shortText(draft.body || '', 900),
      cta: shortText(draft.cta || '', 140),
      hashtags: ensureArray(draft.hashtags).slice(0, 8).map((tag) => shortText(tag, 30)),
    })),
  };
}

const totalStages = 9;

function stagePercent(step, phase) {
  const base = Math.round((Number(step) / totalStages) * 100);
  const adjusted = phase === 'start' ? Math.max(1, base - 5) : base;
  return Math.max(1, Math.min(99, adjusted));
}

function emitProgress(step, stage, phase, note = '') {
  const pct = stagePercent(step, phase);
  const progress = {
    run_id: ctx.run_id,
    step,
    stage,
    phase,
    pct,
    note: String(note || ''),
    ts: nowIso(),
  };
  ctx.artifacts.progress = progress;
  console.log(
    '[WF90_PROGRESS] run_id=' + progress.run_id
    + ' step=' + progress.step + '/' + totalStages
    + ' pct=' + progress.pct
    + ' stage=' + progress.stage
    + ' phase=' + progress.phase
    + (progress.note ? ' note=' + progress.note.replace(/\s+/g, '_') : '')
    + ' ts=' + progress.ts
  );
}

async function runJsonStrict(systemPrompt, userPrompt, options) {
  return await callOllamaJson.call(this, systemPrompt, userPrompt, options);
}

// Stage 1: Collect Research Daten
emitProgress(1, 'collect_research_daten', 'start');
const baseQueries = [
  ctx.topic_hint ? String(ctx.topic_hint) + ' b2b datenanalyse praxis' : null,
  'b2b analytics reporting pain points 2026',
  'data infrastructure saas trends 2026',
  'site:reddit.com dataengineering dashboard reporting',
  'site:reddit.com SideProject openrouter exa serp',
].filter(Boolean);

const rawSignals = [];
const failedQueries = [];

for (const query of baseQueries.slice(0, 4)) {
  try {
    const response = await callSearx.call(this, query);
    const results = ensureArray(response.results).slice(0, 4);
    for (const result of results) {
      rawSignals.push({
        query,
        source_type: query.includes('site:reddit.com') ? 'searx_reddit' : 'web',
        title: String(result.title || ''),
        url: String(result.url || ''),
        summary: String(result.content || result.snippet || ''),
        published_at: String(result.publishedDate || ''),
      });
    }
  } catch (error) {
    failedQueries.push({ query, reason: String(error.message || 'unknown') });
  }
}

if (!rawSignals.length) {
  throw new Error('No research signals collected. Failed queries: ' + JSON.stringify(failedQueries));
}

ctx.artifacts.raw_signals = rawSignals;
addStage(
  1,
  'collect_research_daten',
  'ok',
  'run/' + ctx.run_id + '/stage1/input',
  'run/' + ctx.run_id + '/stage1/raw_signals',
  rawSignals.length >= 6 ? 8.5 : 6.5,
  'signals=' + rawSignals.length + '; failed_queries=' + failedQueries.length,
  failedQueries.length
);
await addStageSummary.call(this, 1, 'collect_research_daten', JSON.stringify(rawSignals.slice(0, 6)));
emitProgress(1, 'collect_research_daten', 'done', 'signals=' + rawSignals.length);

// Stage 2: Build Evidence Paket
emitProgress(2, 'build_evidence_paket', 'start');
let evidencePackets = rawSignals.slice(0, 12).map((signal) => {
  const pointA = shortText(signal.title || 'Signal ohne Titel', 120);
  const pointB = shortText(signal.summary || 'Keine Zusammenfassung verfuegbar.', 140);
  const isReddit = String(signal.source_type || '').includes('reddit');
  return {
    query: String(signal.query || ''),
    source_type: String(signal.source_type || 'web'),
    title: String(signal.title || ''),
    url: String(signal.url || ''),
    published_at: String(signal.published_at || ''),
    summary: String(signal.summary || ''),
    key_points: [pointA, pointB].filter(Boolean),
    icp_fit_score: isReddit ? 0.62 : 0.74,
    product_relevance_score: isReddit ? 0.58 : 0.71,
    evidence_strength: String(signal.url || '').startsWith('http') ? 0.69 : 0.48,
    risk_notes: [isReddit ? 'community_signal' : 'web_signal'],
  };
});

ctx.artifacts.evidence_packets = evidencePackets;
addStage(
  2,
  'build_evidence_paket',
  'ok',
  'run/' + ctx.run_id + '/stage2/input',
  'run/' + ctx.run_id + '/stage2/evidence_packets',
  average(evidencePackets.map((p) => p.evidence_strength)),
  'packets=' + evidencePackets.length
);
await addStageSummary.call(this, 2, 'build_evidence_paket', JSON.stringify(evidencePackets.slice(0, 4)));
emitProgress(2, 'build_evidence_paket', 'done', 'packets=' + evidencePackets.length);

// Stage 3: Build Topic Brief
emitProgress(3, 'build_topic_brief', 'start');
const stage3Prompt = [
  ctx.prompts.agent2_topic_fit,
  'Return JSON only.',
  'Evidence packets: ' + JSON.stringify(compactEvidence(evidencePackets, 4)),
].join('\n\n');

const stage3 = await runJsonStrict.call(
  this,
  'You are a product strategy reviewer. Return valid JSON only.',
  stage3Prompt,
  { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 180000, max_attempts: 3 }
);

const topicBrief = stage3.parsed;
validateTopicBrief(topicBrief);
topicBrief.confidence = clamp(topicBrief.confidence, 0, 1, 0.5);
if (!Array.isArray(topicBrief.platform_recommendation) || !topicBrief.platform_recommendation.length) {
  topicBrief.platform_recommendation = ['linkedin', 'reddit'];
}

ctx.artifacts.topic_brief = topicBrief;
addStage(
  3,
  'build_topic_brief',
  'ok',
  'run/' + ctx.run_id + '/stage3/input',
  'run/' + ctx.run_id + '/stage3/topic_brief',
  topicBrief.confidence,
  shortText(topicBrief.angle, 160)
);
await addStageSummary.call(this, 3, 'build_topic_brief', JSON.stringify(topicBrief));
emitProgress(3, 'build_topic_brief', 'done', shortText(topicBrief.topic, 40));

// Stage 4: Build LinkedIn Fokus
emitProgress(4, 'build_linkedin_fokus', 'start');
const stage4Prompt = [
  ctx.prompts.platform_linkedin,
  'Return JSON only.',
  'Topic brief: ' + shortText(JSON.stringify(topicBrief), 1200),
  'Evidence packets: ' + JSON.stringify(compactEvidence(evidencePackets, 3)),
].join('\n\n');

const stage4 = await runJsonStrict.call(
  this,
  'You format research for LinkedIn. Return valid JSON only.',
  stage4Prompt,
  { temperature: 0.2, num_predict: 110, num_ctx: 768, timeout: 150000, max_attempts: 3 }
);

const linkedinResearch = stage4.parsed;
validatePlatformResearch('linkedin_research', linkedinResearch);
ctx.artifacts.linkedin_research = linkedinResearch;
